// syncResourcePath maps resource names to their actual API endpoint paths.
// For REST APIs this is typically "/<resource>". For non-REST APIs (e.g., Steam)
// this preserves the actual endpoint path like "/ISteamApps/GetAppList/v2".
func syncResourcePath(resource string) (string, error) {
	paths := map[string]string{
		"account-calendars": "/account_calendars",
		"accounts": "/accounts",
		"appointment-groups": "/appointment_groups",
		"audit": "/audit/grade_change",
		"calendar-events": "/calendar_events",
		"canvas-lms-search": "/search/recipients",
		"canvas-lms-search-all-courses": "/search/all_courses",
		"conferences": "/conferences",
		"conversations": "/conversations",
		"conversations-batches": "/conversations/batches",
		"conversations-find-recipients": "/conversations/find_recipients",
		"course-accounts": "/course_accounts",
		"course-creation-accounts": "/course_creation_accounts",
		"courses": "/courses",
		"epub-exports": "/epub_exports",
		"manageable-accounts": "/manageable_accounts",
		"media-attachments": "/media_attachments",
		"media-objects": "/media_objects",
		"planner": "/planner/items",
		"planner-notes": "/planner_notes",
		"planner-overrides": "/planner/overrides",
		"users": "/users/self/todo",
		"users-self-course-nicknames": "/users/self/course_nicknames",
		"users-self-favorites-courses": "/users/self/favorites/courses",
		"users-self-favorites-groups": "/users/self/favorites/groups",
		"users-self-groups": "/users/self/groups",
	}
	if p, ok := paths[resource]; ok {
		return p, nil
	}
	return "", fmt.Errorf("unknown sync resource %q", resource)
}

